SELECT total_population
FROM country_stats
WHERE year = 1;

SELECT total_population
FROM country_stats
WHERE country_id = 1 AND year = 1;

SELECT SUM(total_military_spending_usd) AS total_spending
FROM country_stats
WHERE country_id = 0;

SELECT MAX(total_military_spending_usd) AS max_military_spending
FROM country_stats
WHERE country_id = 1 AND year = 1;

SELECT country_id
FROM country_income_groups
WHERE income_group_id = 0;

SELECT year, SUM(total_military_spending_usd) AS total_spending
FROM country_stats
GROUP BY year;
